// ADAPTEZ ce mapping au format reel de votre API de metriques.
// Programmation defensive : la source peut etre en erreur (onError: continue) ou renvoyer un format inattendu.
const brut = $input.first().json || {};
const enErreur = Boolean(brut.error);

const num = (v) => (typeof v === 'number' && isFinite(v)) ? v : (parseFloat(v) || 0);

// Exemple de mapping — remplacez par vos indicateurs reels :
const indicateurs = [
  { nom: 'Visites du site', valeur: num(brut.visites), unite: '' },
  { nom: 'Inscriptions newsletter', valeur: num(brut.inscriptions), unite: '' },
  { nom: 'Taux d\'ouverture email', valeur: num(brut.tauxOuverture), unite: '%' },
  { nom: 'Leads generes', valeur: num(brut.leads), unite: '' }
];

return [{
  json: {
    date: new Date().toISOString().split('T')[0],
    enErreur,
    messageErreur: enErreur ? (brut.error?.message || 'Source de metriques injoignable') : '',
    indicateurs
  }
}];

const d = $input.first().json;

const lignes = d.indicateurs.map(i =>
  `<tr><td style="padding:8px;border-bottom:1px solid #eee;">${i.nom}</td><td style="padding:8px;border-bottom:1px solid #eee;text-align:right;font-weight:bold;">${i.valeur}${i.unite}</td></tr>`
).join('');

const avertissement = d.enErreur
  ? `<p style="color:#e74c3c;font-weight:bold;">⚠ La source de métriques n'a pas répondu correctement : ${d.messageErreur}. Les valeurs ci-dessous peuvent être incomplètes.</p>`
  : '';

const html = `<div style="font-family: Helvetica, Arial, sans-serif; font-size: 12pt; color: #333; line-height: 1.6; max-width: 600px;">
  <p style="font-size: 14pt; font-weight: bold;">Rapport marketing quotidien — ${d.date}</p>
  ${avertissement}
  <table style="border-collapse: collapse; width: 100%; margin: 16px 0;">
    <tr style="background:#f0f0f0;"><th style="padding:8px;text-align:left;">Indicateur</th><th style="padding:8px;text-align:right;">Valeur</th></tr>
    ${lignes}
  </table>
  <p style="color:#888;font-size:10pt;">Généré automatiquement par n8n — workflow « Reporting - Envoyer - Rapport quotidien ».</p>
</div>`;

return [{ json: { sujet: `Rapport marketing — ${d.date}`, corps: html } }];
